# Automate EC2 OS hardening via SSM Run Command at launch
resource "aws_ssm_document" "harden_os" {
  name          = "HardenOSBaseline"
  document_type = "Command"
  content = jsonencode({
    schemaVersion = "2.2"
    description   = "Apply OS hardening baseline"
    mainSteps = [{
      action = "aws:runShellScript"
      name   = "harden"
      inputs = {
        runCommand = [
          "systemctl disable telnet",
          "sed -i 's/^PermitRootLogin.*/PermitRootLogin no/' /etc/ssh/sshd_config",
          "sed -i 's/^PasswordAuthentication.*/PasswordAuthentication no/' /etc/ssh/sshd_config",
          "systemctl reload sshd"
        ]
      }
    }]
  })
}

# Enforce IMDSv2 in an EC2 Launch Template
resource "aws_launch_template" "app" {
  name_prefix   = "app-"
  image_id      = data.aws_ami.amazon_linux.id
  instance_type = "t3.medium"

  metadata_options {
    http_endpoint               = "enabled"
    http_tokens                 = "required"  # IMDSv2 only
    http_put_response_hop_limit = 1           # prevent container-to-host credential theft
  }

  iam_instance_profile {
    name = aws_iam_instance_profile.app.name
  }
}

# Retrieve secret in Lambda using Parameters and Secrets Extension
# (caches in memory — avoids API call overhead per invocation)
import urllib.request, json, os

PORT = os.environ.get("PARAMETERS_SECRETS_EXTENSION_HTTP_PORT", "2773")
SECRET_ARN = os.environ["DB_SECRET_ARN"]

def get_secret():
    url = f"http://localhost:{PORT}/secretsmanager/get?secretId={SECRET_ARN}"
    req = urllib.request.Request(url, headers={
        "X-Aws-Parameters-Secrets-Token": os.environ["AWS_SESSION_TOKEN"]
    })
    with urllib.request.urlopen(req) as resp:
        return json.loads(json.loads(resp.read())["SecretString"])

# AWS FIS: simulate an AZ failure to test multi-AZ failover
resource "aws_fis_experiment_template" "az_failure" {
  description = "Simulate AZ failure for RDS Multi-AZ failover test"
  role_arn    = aws_iam_role.fis.arn

  stop_condition {
    source = "aws:cloudwatch:alarm"
    value  = aws_cloudwatch_metric_alarm.error_rate.arn
  }

  action {
    name      = "failover-rds"
    action_id = "aws:rds:failover-db-cluster"
    target    { key = "Clusters"; value = "cluster-target" }
  }

  target {
    name           = "cluster-target"
    resource_type  = "aws:rds:cluster"
    selection_mode = "ALL"
    resource_tag   { key = "Environment"; value = "staging" }
  }
}
